      </a>
    </div>
  </div>
</section>

<!-- CTA BANNER -->
<section style="background: #203559; color: white; padding: 80px 5%; text-align: center;">
  <div class="sam-container" style="max-width: 700px;">
    <h2 style="font-size: 2.5rem; margin: 0 0 16px 0; line-height: 1.2;">Monitor your hardest-to-reach assets</h2>
