   SAMOTICS PROOF / CUSTOMER STORY PAGE — CSS
   ArcelorMittal (thyssenkrupp.html) Customer Page
   Extends homepage tokens (loaded via header)
   ============================================================ */

:root {
  --sam-white: #ffffff;
  --sam-black: #000000;
  --sam-space-cadet: #203559;
  --sam-comet: #5a6c7d;
  --sam-seashell: #f8f6f3;
  --sam-orange: #FF6B35;
  --sam-orange-dark: #E55A24;
  --sam-border-light: #e0dcd8;
  --sam-font: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  --ease: 0.3s ease;
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.1);
  --sp-01: 4px;
  --sp-02: 8px;
  --sp-03: 12px;
  --sp-04: 16px;
  --sp-05: 20px;
  --sp-06: 24px;
  --sp-07: 32px;
  --sp-08: 40px;
  --sp-09: 48px;
  --sp-10: 56px;
  --sp-11: 64px;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--sam-font);
  background: var(--sam-white);
}

.sam-container {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
}

/* ── Breadcrumb ── */
.sam-breadcrumb ol {
  list-style: none;
  margin: 0 0 var(--sp-06) 0;
  padding: 0;
  display: flex;
  gap: var(--sp-03);
  font-family: var(--sam-font);
  font-size: 0.875rem;
}
.sam-breadcrumb li {
  display: flex;
  align-items: center;
  gap: var(--sp-03);
}
.sam-breadcrumb li + li::before {
  content: "/";
  color: rgba(255,255,255,0.4);
}
.sam-breadcrumb a {
  color: rgba(255,255,255,0.7);
  text-decoration: none;
  transition: color var(--ease);
}
.sam-breadcrumb a:hover {
  color: var(--sam-white);
}
.sam-breadcrumb [aria-current="page"] {
  color: var(--sam-white);
  font-weight: 500;
}

/* ── Hero ── */
.sam-hero {
  min-height: 480px;
  display: flex;
  align-items: center;
  padding: var(--sp-11) 0;
}

.sam-hero--proof {
  min-height: 480px;
}

.overline {
  font-family: var(--sam-font);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  font-weight: 600;
  margin: 0;
}

/* ── KPI Strip (navy bg → white text, orange KPI values) ── */
.sam-proof-kpis {
  background: var(--sam-space-cadet);
  padding: var(--sp-08) 0;
}
.sam-proof-kpis__inner {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--sp-07);
  text-align: center;
}
.sam-proof-kpis__item {
  display: flex;
  flex-direction: column;
  gap: var(--sp-02);
}
.sam-proof-kpis__value {
  font-size: 2.5rem;
  line-height: 1.1;
  color: var(--sam-orange);
  font-weight: 700;
}
.sam-proof-kpis__label {
  font-family: var(--sam-font);
  font-weight: 500;
  font-size: 0.875rem;
  color: rgba(255,255,255,0.7);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

/* ── Customer Overview (white bg → navy accent) ── */
.sam-proof-overview {
  background: var(--sam-white);
  padding: var(--sp-11) 0;
}
.sam-proof-overview__inner {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: var(--sp-09);
}
.sam-proof-overview__logo {
  background: var(--sam-seashell);
  border: 1px solid var(--sam-border-light);
  padding: var(--sp-07);
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--sam-font);
  font-weight: 700;
  font-size: 1.25rem;
  color: var(--sam-space-cadet);
  min-height: 120px;
  margin-bottom: var(--sp-06);
  text-align: center;
}
.sam-proof-overview__meta {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: var(--sp-03) var(--sp-05);
  font-family: var(--sam-font);
  font-size: 0.9375rem;
  margin: 0;
}
.sam-proof-overview__meta dt {
  font-weight: 600;
  color: var(--sam-space-cadet);
}
.sam-proof-overview__meta dd {
  margin: 0;
  color: var(--sam-comet);
}
.sam-proof-overview__body .overline {
  color: var(--sam-space-cadet);
}
.sam-proof-overview__body h2 {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 2.5rem;
  line-height: 1.2;
  letter-spacing: -0.01em;
  color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-06) 0;
}
.sam-proof-overview__body p {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 1.0625rem;
  line-height: 1.7;
  color: var(--sam-black);
  margin: 0 0 var(--sp-05) 0;
  max-width: 65ch;
}

/* ── Challenge (seashell bg → orange accent) ── */
.sam-proof-challenge {
  background: var(--sam-seashell);
  padding: var(--sp-11) 0;
}
.sam-proof-challenge__inner {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
}
.sam-proof-challenge__inner .overline {
  color: var(--sam-orange);
}
.sam-proof-challenge__inner h2 {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 2.5rem;
  line-height: 1.2;
  letter-spacing: -0.01em;
  color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-07) 0;
  max-width: 30ch;
}
.sam-proof-challenge__content {
  max-width: 65ch;
}
.sam-proof-challenge__content p {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 1.0625rem;
  line-height: 1.7;
  color: var(--sam-black);
  margin: 0 0 var(--sp-05) 0;
}

/* ── Solution (white bg → navy accent) ── */
.sam-proof-solution {
  background: var(--sam-white);
  padding: var(--sp-11) 0;
}
.sam-proof-solution__inner {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-09);
  align-items: center;
}
.sam-proof-solution__text .overline {
  color: var(--sam-space-cadet);
}
.sam-proof-solution__text h2 {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 2.5rem;
  line-height: 1.2;
  letter-spacing: -0.01em;
  color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-06) 0;
}
.sam-proof-solution__text p {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 1.0625rem;
  line-height: 1.7;
  color: var(--sam-black);
  margin: 0 0 var(--sp-05) 0;
  max-width: 55ch;
}
.sam-proof-solution__placeholder {
  background: var(--sam-seashell);
  border: 1px solid var(--sam-border-light);
  aspect-ratio: 16/10;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--sam-font);
  color: var(--sam-comet);
  font-size: 0.875rem;
}

/* ── Results (seashell bg → orange accent) ── */
.sam-proof-results {
  background: var(--sam-seashell);
  padding: var(--sp-11) 0;
}
.sam-proof-results__inner {
  max-width: 1584px;
  margin: 0 auto;
  padding: 0 5%;
}
.sam-proof-results__inner .overline {
  color: var(--sam-orange);
}
.sam-proof-results__inner h2 {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 2.5rem;
  line-height: 1.2;
  letter-spacing: -0.01em;
  color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-08) 0;
}
.sam-proof-results__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--sp-06);
}
.sam-proof-results__card {
  background: var(--sam-white);
  border: 1px solid var(--sam-border-light);
  border-top: 3px solid var(--sam-orange);
  padding: var(--sp-07);
  display: flex;
  flex-direction: column;
  gap: var(--sp-04);
}
.sam-proof-results__card-value {
  font-size: 2.5rem;
  line-height: 1.1;
  color: var(--sam-orange);
  font-weight: 700;
}
.sam-proof-results__card h3 {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 1.125rem;
  line-height: 1.3;
  color: var(--sam-space-cadet);
  margin: 0;
}
.sam-proof-results__card p {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: var(--sam-black);
  margin: 0;
}

/* ── Quote (white bg → navy accent) ── */
.sam-proof-quote {
  background: var(--sam-white);
  padding: var(--sp-11) 0;
}
.sam-proof-quote__inner {
  max-width: 800px;
  margin: 0 auto;
  padding: 0 5%;
}
.sam-proof-quote__inner blockquote {
  border-left: 3px solid var(--sam-space-cadet);
  padding-left: var(--sp-07);
