  color: var(--sam-space-cadet);
  font-style: italic;
  margin: 0 0 var(--sp-06) 0;
}
.sam-proof-quote__inner blockquote footer {
  display: flex;
  flex-direction: column;
  gap: var(--sp-01);
}
.sam-proof-quote__inner blockquote footer strong {
  font-family: var(--sam-font);
