}
.sam-proof-quote__inner blockquote footer span {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 0.875rem;
  color: var(--sam-comet);
}

/* ── Related Stories (seashell bg → orange accent) ── */
.sam-proof-related {
  background: var(--sam-seashell);
  padding: var(--sp-11) 0;
}
.sam-proof-related__inner {
  max-width: 1584px;
  margin: 0 auto;
