}

/* ── Focus Styles ── */
.sam-proof-related__card:focus-visible {
  outline: 3px solid var(--sam-orange);
  outline-offset: 2px;
}

/* ── Reduced Motion ── */
@media (prefers-reduced-motion: reduce) {
  .sam-proof-related__card {
    transition: none !important;
  }
}

/* ============================================================
   RESPONSIVE
   ============================================================ */

@media (max-width: 1055px) {
  .sam-proof-kpis__inner {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--sp-08);
  }
  .sam-proof-overview__inner {
