a:1:{i:0;a:5:{s:2:"id";s:6:"9delhk";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"2f72763cd9019019c382e4f1a5f99d0f";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:8691:"<!-- ============================================================
     SAMOTICS CASE STUDIES ARCHIVE — HTML
     Paste into Bricks Page → Add Code Element → HTML tab
     Then add case-studies-archive.css to CSS tab
     Then add case-studies-archive.js to Custom Code (footer)

     NOTE: This page uses WordPress WP_Query to fetch case study posts
     Use the filter chips to filter by category (?cat= parameter)
     ============================================================ -->

<main class="sam-case-studies">
  <!-- ──────────────────────────────────────────────────────
       SECTION 1: HERO
       ────────────────────────────────────────────────────── -->
  <section class="sam-case-studies__hero" style="background: #F5F6F8;">
    <div class="sam-case-studies__hero-content">
      <p class="overline" style="color: #FF5429;">Case Studies</p>
      <h1 class="sam-case-studies__hero-title">Every detection. Documented.</h1>
      <p class="lead" style="color: #1F1F33; max-width: 70ch;">Browse 35+ real-world fault detections across industries, asset types, and outcomes.</p>
    </div>
  </section>

  <!-- ──────────────────────────────────────────────────────
       SECTION 2: FILTER & GRID
       ────────────────────────────────────────────────────── -->
  <section class="sam-case-studies__content" style="background: #FFFFFF;">
    <div class="sam-case-studies__container">
      <!-- Filter Chips -->
      <div class="sam-case-studies__filters">
        <a href="/proof/case-studies/" class="sam-case-studies__filter-chip sam-case-studies__filter-chip--active" data-filter="all">
          All
        </a>
        <a href="/proof/case-studies/?cat=water" class="sam-case-studies__filter-chip" data-filter="water">
          Water
        </a>
        <a href="/proof/case-studies/?cat=oil-gas" class="sam-case-studies__filter-chip" data-filter="oil-gas">
          Oil & Gas
        </a>
        <a href="/proof/case-studies/?cat=metals-mining" class="sam-case-studies__filter-chip" data-filter="metals-mining">
          Metals & Mining
        </a>
        <a href="/proof/case-studies/?cat=chemicals" class="sam-case-studies__filter-chip" data-filter="chemicals">
          Chemicals
        </a>
        <a href="/proof/case-studies/?cat=infrastructure" class="sam-case-studies__filter-chip" data-filter="infrastructure">
          Infrastructure
        </a>
      </div>

      <!-- Case Study Cards Grid -->
      <div class="sam-case-studies__grid">
        <!-- Example card 1 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #D6F5F1; color: #0098AC;">Water & Wastewater</div>
          <h3 class="sam-case-studies__card-title">Detecting Bearing Failure in Municipal Pump Before Catastrophic Collapse</h3>
          <p class="sam-case-studies__card-excerpt">A water treatment authority deployed SAM4 on their primary circulation pump and detected progressive bearing wear 6 weeks before failure was imminent.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>

        <!-- Example card 2 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #FFE8D6; color: #FF5429;">Oil & Gas</div>
          <h3 class="sam-case-studies__card-title">Predictive Detection of Cavitation in Offshore Transfer Pump</h3>
          <p class="sam-case-studies__card-excerpt">Real-time electrical signatures revealed cavitation damage in an offshore platform pump, preventing an estimated $2M in unplanned maintenance costs.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>

        <!-- Example card 3 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #E8D6F5; color: #7B2CBF;">Metals & Mining</div>
          <h3 class="sam-case-studies__card-title">Detecting Misalignment in Crusher Motor Before Gearbox Failure</h3>
          <p class="sam-case-studies__card-excerpt">SAM4 identified angular misalignment in a crusher drive system's coupling. Preventive realignment avoided a projected 5-day production shutdown.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>

        <!-- Example card 4 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #E8F4FF; color: #005CBA;">Chemicals</div>
          <h3 class="sam-case-studies__card-title">Real-Time Detection of Multi-Fault Condition in Reactor Feed Pump</h3>
          <p class="sam-case-studies__card-excerpt">Three simultaneous faults detected in a critical process pump: bearing wear, belt slippage, and cavitation—each at different stages of development.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>

        <!-- Example card 5 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #D6F5F1; color: #0098AC;">Water & Wastewater</div>
          <h3 class="sam-case-studies__card-title">Preventive Detection of Blockage in Sewage Treatment Submersible</h3>
          <p class="sam-case-studies__card-excerpt">ESA identified inlet blockage in a submersible pump before it stalled completely, enabling scheduled maintenance rather than emergency replacement.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>

        <!-- Example card 6 -->
        <article class="sam-case-studies__card">
          <div class="sam-case-studies__card-tag" style="background: #FFE8D6; color: #FF5429;">Oil & Gas</div>
          <h3 class="sam-case-studies__card-title">Monitoring Thermal Stress in High-Speed Compressor Motor</h3>
          <p class="sam-case-studies__card-excerpt">Continuous electrical signature analysis revealed motor winding degradation that had been missed by traditional temperature monitoring.</p>
          <a href="#" class="sam-case-studies__card-link">Read case study →</a>
        </article>
      </div>

      <!-- Pagination (if using WordPress) -->
      <div class="sam-case-studies__pagination" style="text-align: center; margin-top: var(--sp-10); padding-top: var(--sp-08); border-top: 1px solid var(--sam-border-light);">
        <nav style="display: flex; gap: var(--sp-04); justify-content: center; align-items: center; flex-wrap: wrap;">
          <a href="#" class="sam-case-studies__pagination-link" style="color: #5A6A80; text-decoration: none; padding: 8px 12px; border: 1px solid var(--sam-border-light); border-radius: 4px; font-family: var(--sam-font);">← Previous</a>
          <span style="color: #1F1F33; font-family: var(--sam-font); font-weight: 600;">Page 1 of 3</span>
          <a href="#" class="sam-case-studies__pagination-link" style="color: var(--sam-orange); text-decoration: none; padding: 8px 12px; border: 1px solid var(--sam-orange); border-radius: 4px; font-family: var(--sam-font); font-weight: 600;">Next →</a>
        </nav>
      </div>
    </div>
  </section>

  <!-- ──────────────────────────────────────────────────────
       SECTION 3: CTA BANNER
       ────────────────────────────────────────────────────── -->
  <section class="sam-case-studies__cta-banner" style="background: #1F1F33; padding: var(--sp-10) var(--sp-06);">
    <div class="sam-case-studies__container" style="text-align: center;">
      <h2 style="color: #FFFFFF; margin: 0 0 var(--sp-06) 0;">Want to add your name to this list?</h2>
      <p style="color: #E2E4E8; font-size: 1rem; margin: 0 0 var(--sp-08) 0; max-width: 60ch; margin-left: auto; margin-right: auto;">See how SAM4 can prevent failures and optimize operations at your facility.</p>
      <a href="/contact/" class="sam-btn sam-btn--primary" style="background: #FF5429; color: #111111;">Request Demo</a>
    </div>
  </section>
</main>
";s:7:"cssCode";s:10168:"/* ============================================================
   SAMOTICS CASE STUDIES ARCHIVE — CSS
   Paste into Bricks Code Element → CSS tab
   ============================================================ */

/* ── Tokens (extend header/footer tokens) ── */
:root {
  /* Core Palette */
  --sam-space-cadet:     #1F1F33;
  --sam-orange:          #FF5429;
  --sam-orange-dark:     #D7411B;
  --sam-orange-deep:     #A33013;
  --sam-blue:            #005CBA;
  --sam-blue-dark:       #004179;
  --sam-blue-light:      #B3DAFF;
  --sam-teal:            #0098AC;
  --sam-teal-dark:       #006C6C;
  --sam-white:           #FFFFFF;
  --sam-seashell:        #F5F6F8;
  --sam-black:           #111111;
  --sam-comet:           #5A6A80;
  --sam-muted-dark:      #B0B0C8;
  --sam-border-light:    #E2E4E8;
  --sam-dark-elevated:   #2A2A42;
  --sam-gold:            #FAC91F;

  /* Fonts */
  --sam-font:  'IBM Plex Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  --sam-mono:  'JetBrains Mono', "SFMono-Regular", Consolas, "Liberation Mono", Menlo, Courier, monospace;

  /* Spacing */
  --sp-01: 2px;
  --sp-02: 4px;
  --sp-03: 8px;
  --sp-04: 12px;
  --sp-05: 16px;
  --sp-06: 24px;
  --sp-07: 32px;
  --sp-08: 48px;
  --sp-09: 64px;
  --sp-10: 96px;
  --sp-11: 128px;
  --sp-12: 160px;

  /* Shadows */
  --shadow-sm:  0 1px 3px rgba(31,31,51,0.08);
  --shadow-md:  0 4px 12px rgba(31,31,51,0.10);
  --shadow-lg:  0 12px 32px rgba(31,31,51,0.14);
  --shadow-cta: 0 4px 16px rgba(255,84,41,0.25);

  /* Transitions */
  --ease: 150ms ease-out;
}

/* ── Reset for main ── */
.sam-case-studies {
  overflow-x: hidden;
}

/* ── Shared: Overline ── */
.overline {
  font-family: var(--sam-font);
  font-weight: 600;
  font-size: 0.75rem;
  line-height: 1;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin: 0 0 var(--sp-06) 0;
}

/* ── Shared: Lead ── */
.lead {
  font-family: var(--sam-font);
  font-weight: 400;
  font-size: 1.25rem;
  line-height: 1.6;
  color: var(--sam-space-cadet);
  max-width: 60ch;
  margin: 0;
}

/* ── Shared: Buttons ── */
.sam-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 14px 32px;
  font: 600 1rem/1 var(--sam-font);
  letter-spacing: 0.02em;
  text-decoration: none;
  border: none;
  cursor: pointer;
  transition: background-color var(--ease), color var(--ease), box-shadow var(--ease), border-color var(--ease);
  white-space: nowrap;
}
.sam-btn:focus-visible {
  outline: 3px solid var(--sam-orange);
  outline-offset: 2px;
}

/* Primary: Orange */
.sam-btn--primary {
  background: var(--sam-orange);
  color: var(--sam-black);
}
.sam-btn--primary:hover {
  background: var(--sam-orange-dark);
  color: var(--sam-white);
  box-shadow: var(--shadow-cta);
}
.sam-btn--primary:active {
  background: var(--sam-orange-deep);
  color: var(--sam-white);
}

/* ────────────────────────────────────────────────────────
   HERO SECTION
   ──────────────────────────────────────────────────────── */
.sam-case-studies__hero {
  padding: var(--sp-10) var(--sp-06);
  min-height: 300px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.sam-case-studies__hero-content {
  max-width: 900px;
  width: 100%;
  margin: 0 auto;
}

.sam-case-studies__hero-title {
  font-family: var(--sam-font);
  font-size: 3rem;
  font-weight: 700;
  line-height: 1.2;
  color: var(--sam-space-cadet);
  margin: var(--sp-06) 0 var(--sp-06) 0;
}

/* ────────────────────────────────────────────────────────
   CONTAINER & SHARED STYLES
   ──────────────────────────────────────────────────────── */
.sam-case-studies__container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 var(--sp-06);
}

/* ────────────────────────────────────────────────────────
   CONTENT SECTION
   ──────────────────────────────────────────────────────── */
.sam-case-studies__content {
  padding: var(--sp-10) var(--sp-06);
}

/* ────────────────────────────────────────────────────────
   FILTERS
   ──────────────────────────────────────────────────────── */
.sam-case-studies__filters {
  display: flex;
  gap: var(--sp-04);
  flex-wrap: wrap;
  margin-bottom: var(--sp-10);
  justify-content: center;
}

.sam-case-studies__filter-chip {
  font-family: var(--sam-font);
  font-size: 0.95rem;
  font-weight: 600;
  padding: 10px 20px;
  border-radius: 24px;
  border: 2px solid var(--sam-border-light);
  background: var(--sam-white);
  color: var(--sam-space-cadet);
  text-decoration: none;
  transition: all var(--ease);
  cursor: pointer;
}

.sam-case-studies__filter-chip:hover {
  border-color: var(--sam-orange);
  color: var(--sam-orange);
}

.sam-case-studies__filter-chip--active {
  background: var(--sam-orange);
  color: var(--sam-white);
  border-color: var(--sam-orange);
}

/* ────────────────────────────────────────────────────────
   CASE STUDY GRID
   ──────────────────────────────────────────────────────── */
.sam-case-studies__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--sp-08);
  margin-bottom: var(--sp-10);
}

.sam-case-studies__card {
  background: var(--sam-white);
  padding: var(--sp-08);
  border-radius: 8px;
  border: 2px solid var(--sam-border-light);
  transition: all var(--ease);
  display: flex;
  flex-direction: column;
}

.sam-case-studies__card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-lg);
  border-color: var(--sam-orange);
}

.sam-case-studies__card-tag {
  display: inline-block;
  font-family: var(--sam-font);
  font-size: 0.75rem;
  font-weight: 600;
  padding: 6px 12px;
  border-radius: 4px;
  width: fit-content;
  margin-bottom: var(--sp-06);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.sam-case-studies__card-title {
  font-family: var(--sam-font);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-04) 0;
  line-height: 1.4;
}

.sam-case-studies__card-excerpt {
  font-family: var(--sam-font);
  font-size: 0.95rem;
  line-height: 1.6;
  color: var(--sam-comet);
  margin: 0;
  flex-grow: 1;
  margin-bottom: var(--sp-06);
}

.sam-case-studies__card-link {
  font-family: var(--sam-font);
  color: var(--sam-orange);
  text-decoration: none;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: color var(--ease);
}

.sam-case-studies__card-link:hover {
  color: var(--sam-orange-dark);
}

/* ────────────────────────────────────────────────────────
   PAGINATION
   ──────────────────────────────────────────────────────── */
.sam-case-studies__pagination-link {
  transition: all var(--ease);
}

.sam-case-studies__pagination-link:hover {
  background: var(--sam-orange) !important;
  color: var(--sam-white) !important;
}

/* ────────────────────────────────────────────────────────
   CTA BANNER
   ──────────────────────────────────────────────────────── */
.sam-case-studies__cta-banner h2 {
  font-family: var(--sam-font);
  font-size: 2rem;
  font-weight: 700;
  line-height: 1.3;
}

.sam-case-studies__cta-banner p {
  font-family: var(--sam-font);
  font-size: 1rem;
  line-height: 1.6;
}

/* ────────────────────────────────────────────────────────
   RESPONSIVE
   ──────────────────────────────────────────────────────── */
@media (max-width: 900px) {
  .sam-case-studies__hero-title {
    font-size: 2.2rem;
  }

  .sam-case-studies__hero {
    min-height: 250px;
    padding: var(--sp-09) var(--sp-06);
  }

  .sam-case-studies__grid {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--sp-06);
  }

  .sam-case-studies__content {
    padding: var(--sp-09) var(--sp-06);
  }
}

@media (max-width: 600px) {
  .sam-case-studies__hero-title {
    font-size: 1.75rem;
  }

  .sam-case-studies__hero {
    min-height: 200px;
    padding: var(--sp-08) var(--sp-05);
  }

  .sam-case-studies__grid {
    grid-template-columns: 1fr;
    gap: var(--sp-06);
  }

  .sam-case-studies__filters {
    gap: var(--sp-03);
    margin-bottom: var(--sp-08);
  }

  .sam-case-studies__filter-chip {
    font-size: 0.85rem;
    padding: 8px 16px;
  }

  .sam-case-studies__cta-banner h2 {
    font-size: 1.5rem;
  }

  .sam-case-studies__content,
  .sam-case-studies__cta-banner {
    padding: var(--sp-08) var(--sp-05);
  }

  .sam-case-studies__container {
    padding: 0 var(--sp-05);
  }
}
";}}}

a:1:{i:0;a:5:{s:2:"id";s:6:"a070p0";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"0d23d5f1e9dd58657503a089d301be94";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:6744:"<!-- ============================================================
     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/bearing-failure-motor-roll
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Bearing failure avoided in motor driving critical runout table roll</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Motor driving runout table roll</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Bearing degradation</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Steel manufacturing</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Monitoring period</span>
          <span class="sam-detect-summary__value kpi-value">7 months</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">A motor driving a critical runout table roll in a steel mill showed early signs of bearing degradation. The customer had more than two dozen prior SAM4 detections on their fleet, so they trusted the system to track the fault progression and advise on timing.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 detected an increase in energy at the bearing cage (FTF) frequency and its harmonics. Samotics alerted the customer to developing but non-urgent damage and placed the asset under close observation. Over the next seven months, the customer received regular status updates. When the energy rise reached a level that warranted timely action, the customer replaced the motor and roll during a scheduled maintenance window. Energy levels returned to normal.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">No unplanned downtime. The customer had the full picture of bearing degradation progression — from early detection through to recommended intervention timing. SAM4 has detected more than two dozen faults for this customer, building the trust needed to plan maintenance around its alerts.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;SAM4 has detected more than two dozen faults for us, so we know we can rely on the system to tell us when it&rsquo;s time to act. Not too soon, not too late, but right when we need to.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">Customer</span>
          <span class="sam-detect-quote__company">Steel mill maintenance team</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
