a:1:{i:0;a:5:{s:2:"id";s:6:"rx3bc1";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"60d1606ae167d1d6e6fe24d6aa120d95";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:6034:"<!-- ============================================================
     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/belt-degradation-circulation-pump
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Belt degradation detected in a critical circulation pump</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Circulation pump</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Belt degradation</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Chemicals</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Result</span>
          <span class="sam-detect-summary__value kpi-value">Downtime avoided</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">At a chlor-alkali plant, circulation pumps keep highly concentrated salt water flowing — an essential part of the production process. If one pump fails unexpectedly, the entire production line shuts down. SAM4 was installed on several critical assets at the plant, including the belt-driven circulation pumps.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 flagged a sudden increase in spectral energy around the belt frequency of one circulation pump. The system provided the customer with a clear notification recommending that the maintenance team inspect the belt during the next planned stop. The notification included fault type (belt degradation), the indicator (belt frequency), and a specific action: inspect and replace the belt.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">The customer inspected the pump during a planned maintenance window — no production losses, no emergency callout. They confirmed the belt needed replacement and swapped it out. The plant continued operating as planned. Early detection avoided potential damage to the asset and prevented a full production line shutdown.</p>
      </div>
    </div>
  </section>


  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/belt-driven-assets-detection" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Chemicals</span>
          <h3 class="sam-detect-related__card-title">Belt-driven asset fault detections</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Multiple belt and bearing detections</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/cavitation-anolyte-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Chemicals</span>
          <h3 class="sam-detect-related__card-title">Cavitation in anolyte pump</h3>
          <p class="sam-detect-related__card-outcome kpi-value">&euro;15,000 saved</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/gearbox-misalignment-circulator-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Industrial</span>
          <h3 class="sam-detect-related__card-title">Gearbox-motor misalignment</h3>
          <p class="sam-detect-related__card-outcome kpi-value">7 months advance warning</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
