a:1:{i:0;a:5:{s:2:"id";s:6:"jelk1i";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"5510d29d6eb897b0bf57d2da932b62b1";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:7284:"<!-- ============================================================
     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/belt-driven-assets-detection
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Multi-detection case study</p>
        <h1 class="sam-hero__h1">Preventing downtime on belt-driven assets</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Belt-driven pumps, fans &amp; conveyors</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Belt degradation, bearing &amp; pulley failures</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Chemicals (ATEX zones)</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Result</span>
          <span class="sam-detect-summary__value kpi-value">Hundreds of thousands saved</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">Chemical plants contain belt-driven pumps, conveyors, fans, and compressors that keep the production process running. Many of these assets sit in ATEX zones or harsh environments where workers cannot safely access them for routine inspection. A single belt failure can shut down an entire production line, contaminate product batches, or create safety hazards. Traditional monitoring requires sensors mounted on the asset — impractical in these conditions.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 monitors from the motor control cabinet, making it safe and practical for ATEX zones. Across multiple chemical plant deployments, SAM4 detected: (1) belt degradation on a chlor-alkali circulation pump — flagged through rising energy at the belt frequency, confirmed at next planned stop; (2) bearing and pulley degradation on a Kevlar production exhaust fan — detected just three weeks after installation, preventing contamination of product batches; and (3) belt degradation on a salt conveyor — caught before the belt snapped and halted the production line.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">Each detection was confirmed by maintenance and resolved during planned maintenance windows. No unplanned downtime, no product contamination, no safety incidents. The major advantage: SAM4 sensors install in the MCC, far from ATEX-zoned production systems, reducing the cost of equipment, installation, and cabling compared to traditional techniques.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;The major reason we chose SAM4 is because it&rsquo;s easy to install in the motor control center, far away from our ATEX-zoned production systems. That greatly reduces the cost of equipment, installation and cabling, compared to traditional condition monitoring techniques.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">Joost Cuyckens</span>
          <span class="sam-detect-quote__company">Asset Management Leader, Kuraray</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related sam-detect-related--alt">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/belt-degradation-circulation-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Chemicals</span>
          <h3 class="sam-detect-related__card-title">Belt degradation in circulation pump</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Downtime avoided</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/cavitation-anolyte-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Chemicals</span>
          <h3 class="sam-detect-related__card-title">Cavitation in anolyte pump</h3>
          <p class="sam-detect-related__card-outcome kpi-value">&euro;15,000 saved</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/loose-belt-guard-shot-blasting" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Manufacturing</span>
          <h3 class="sam-detect-related__card-title">Loose belt guard in shot blaster</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Two faults from one fix</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
