     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/borehole-pump-detections
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Multi-detection case study</p>
        <h1 class="sam-hero__h1">Preventing downtime on borehole pumps</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Submerged borehole pumps</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Clogging, VFD issues &amp; mechanical degradation</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Water &amp; Wastewater</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Pump depth</span>
          <span class="sam-detect-summary__value kpi-value">Up to 200 m</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">Borehole pumps are the pumping heart of the water industry — they supply clean water to residential areas. They are also notoriously difficult to monitor: submerged up to 200 metres below ground, in remote locations, impossible to reach with traditional vibration sensors. Lifting a pump for inspection is expensive and time-consuming. Without remote monitoring, faults go undetected until the pump fails.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 installs in the motor control cabinet — not on the pump — making it uniquely suited for submerged assets. Across multiple water utility deployments, SAM4 has detected: (1) clogging from iron buildup, flagged nearly a year in advance through decreasing active power and cavitation signatures; (2) VFD irregularities, where a pump was overshooting maximum current due to misconfigured inverter settings; and (3) mechanical unbalance, detected through a sudden increase in spectral energy at the rotational frequency. In each case, maintenance teams acted on the alert and confirmed the diagnosis.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">Every detection prevented either pump failure, supply disruption, or both. SAM4's ability to monitor from the MCC eliminates the barrier that makes borehole pumps difficult to maintain. Detectable faults include clogging, grid and VFD irregularities, bearing degradation, and various forms of mechanical wear.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;This technology is ideal for borehole pumps. They can be 150&ndash;180 metres below ground, so having to fit a monitor to that borehole pump would be impossible. Having SAM4 in the MCC is easy to set up and easy to maintain.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">James Nobbs</span>
          <span class="sam-detect-quote__company">Groundwater Engineering Manager, Anglian Water</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related sam-detect-related--alt">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/clogging-borehole-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Borehole pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Nearly 1 year advance warning</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-wastewater-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Wastewater pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Debris cleared after alert</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/inlet-screw-monitoring" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Inlet screw monitoring</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Top 3 failure modes detected</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
