<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">45 kW anolyte pump saved from complete breakdown</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Horizontal centrifugal pump (45 kW)</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Cavitation &amp; mechanical seal damage</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Chemicals</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Savings</span>
          <span class="sam-detect-summary__value kpi-value">&euro;15,000</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">A 45 kW horizontal centrifugal pump circulates anolyte in an electrochemical production process. Cavitation — the formation and collapse of vapour bubbles inside the pump — was gradually weakening the mechanical seal. Left unchecked, the seal would fail completely, destroying the pump and requiring a full replacement.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 detected an increase in the current spectrum noise floor around the rotational frequency, combined with a drop in active power — clear indicators of cavitation. When the system flagged sustained cavitation, Samotics alerted the customer to the likely presence of collateral damage. The customer inspected the pump and found that the mechanical seal was beginning to leak.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">The customer conducted a minor seal repair instead of replacing a badly damaged pump. They reported this saved them &euro;15,000 in avoided replacement costs. Early detection turned what would have been a catastrophic failure into a planned, low-cost maintenance action.</p>
      </div>
    </div>
  </section>


  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/cavitation-centrifugal-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Industrial</span>
          <h3 class="sam-detect-related__card-title">Cavitation in centrifugal product pump</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Suboptimal procedure identified</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/belt-degradation-circulation-pump" class="sam-detect-related__card">
