a:1:{i:0;a:5:{s:2:"id";s:6:"8ohtig";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"febb20f8efae0b8cf516a51da953f2e2";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:6169:"<!-- ============================================================
     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/clogging-borehole-pump
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Borehole pump clogging detected nearly one year in advance</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Submerged borehole pump</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Iron buildup causing clogging</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Water &amp; Wastewater</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Advance warning</span>
          <span class="sam-detect-summary__value kpi-value">~1 year</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">A submerged borehole pump operated in an iron-containing well as part of a water utility's clean water supply. Over time, iron deposits accumulated at the pump's inlet — gradually restricting flow and causing the pump to work harder. Because borehole pumps are submerged deep underground, inspection requires lifting the pump to the surface: a costly, time-consuming operation.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 detected patterns of decreasing active power paired with multiple instances of cavitation — clear indicators of progressive clogging. The system flagged the iron deposit nearly a year before it would have caused failure. Samotics sent a notification as soon as the fault started developing. The customer decided to lift the pump from the well and conduct maintenance.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">Following maintenance, SAM4 confirmed the pump's return to healthy behaviour. Without the early warning, the clogging would have led to overheating and a significant loss of water supply capacity. The detection was especially valuable given the pump's submerged nature — there was no other practical way to know the inlet was clogging.</p>
      </div>
    </div>
  </section>


  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/borehole-pump-detections" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Borehole pump fault detections</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Multiple detections on submerged pumps</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-wastewater-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Wastewater pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Debris cleared after alert</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-yorkshire-water-sewage" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Yorkshire Water sewage clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Pollution event prevented</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
