<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Debris clogging detected in wastewater collection pump</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Municipal wastewater collection pump</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Clogging causing cavitation</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Water &amp; Wastewater</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Result</span>
          <span class="sam-detect-summary__value kpi-value">Timely action taken</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">A municipal wastewater collection pump was operating in a network where debris regularly enters the system. When debris clogs the pump intake, the pump starts cavitating — increasing wear on internal components and reducing flow capacity. If left undetected, the pump overheats and fails.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4 flagged a sudden increase in the noise floor around the pump's supply frequency, which continued over the following days. Based on earlier detections, Samotics contacted the customer to report sustained cavitation and suspected clogging. Ten days later, the customer removed debris from the pump's intake. The pump returned to normal operation, confirmed by the SAM4 dashboard.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">The customer acted on the alert before the pump sustained permanent damage. This was one of many such detections SAM4 has made on this type of asset — each one giving the maintenance team enough advance warning to schedule a targeted intervention.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;This is one of many such situations SAM4 has alerted us to, which is always a real help in our ability to take timely action.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">Customer</span>
          <span class="sam-detect-quote__company">Water utility operations team</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related sam-detect-related--alt">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/clogging-borehole-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Borehole pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Nearly 1 year advance warning</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-yorkshire-water-sewage" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Yorkshire Water sewage clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Pollution event prevented</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/inlet-screw-monitoring" class="sam-detect-related__card">
