<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Yorkshire Water prevents pollution event with automated clogging detection</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Sewage pumps (co-located pair)</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Complete blockage in both pumps</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Water &amp; Wastewater</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Result</span>
          <span class="sam-detect-summary__value kpi-value">Pollution prevented</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">Two co-located sewage pumps at a Yorkshire Water pumping station had telemetry systems in place for visibility. One day in September, the telemetry indicated one pump had tripped while the other was still running normally. Since the remaining pump could handle demand temporarily, no immediate intervention was scheduled. But the telemetry was wrong.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">SAM4's automated clogging detection feature signalled that both pumps had actually become completely blocked — a situation that could cause both to fail and trigger a pollution event. SAM4 sent an urgent alert to Yorkshire Water. The maintenance team immediately visited the site and confirmed both pumps were clogged. The telemetry system had generated a false signal. When the team lifted the pumps, they found boots, tyres, and other foreign objects causing the blockages.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">Both pumps were cleared and returned to normal operation — confirmed by the SAM4 dashboard. Without SAM4's alert, the site would have relied on faulty telemetry and the blockages would have gone undetected until overflow. This was the only visibility the team had: the telemetry had failed, and SAM4 was the sole early warning system that worked.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;Temporary issues with the site telemetry meant the only visibility we had was via the Samotics unit. Thanks to the alert system we were able to urgently attend the site, investigate and remove blockages that would have led to pollution of the local environment.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">Simon Rhodes</span>
          <span class="sam-detect-quote__company">Business Transformation Manager, Yorkshire Water</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related sam-detect-related--alt">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/yorkshire-water" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Yorkshire Water</h3>
          <p class="sam-detect-related__card-outcome kpi-value">&pound;9.8M in benefits</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-wastewater-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Wastewater pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Debris cleared after alert</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/clogging-borehole-pump" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Water &amp; Wastewater</span>
          <h3 class="sam-detect-related__card-title">Borehole pump clogging</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Nearly 1 year advance warning</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
