a:1:{i:0;a:5:{s:2:"id";s:6:"nphvbh";s:4:"name";s:4:"code";s:6:"parent";i:0;s:8:"children";a:0:{}s:8:"settings";a:6:{s:11:"executeCode";b:1;s:9:"signature";s:32:"311ecfa9da055a0757504fa9cb7d2d6c";s:7:"user_id";i:1;s:4:"time";i:1772251117;s:4:"code";s:6672:"<!-- ============================================================
     SAMOTICS DETECTION STORY — Bricks Code Element
     URL: /proof/loose-cardan-joint-roll
     Paste each section into the matching tab:
       1. PHP & HTML  →  the markup below
       2. CSS          →  detection-story.css
       3. JavaScript   →  detection-story.js
     ============================================================ -->


<!-- ===================== PHP & HTML ===================== -->

<main id="main-content" class="sam-detect">

  <!-- ─── 1. HERO (compact dark banner) ─── -->
  <section class="sam-hero sam-hero--detect">
    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <p class="sam-hero__overline">Fault detection</p>
        <h1 class="sam-hero__h1">Loose cardan joint caught the same day SAM4 was installed</h1>
      </div>
    </div>
  </section>


  <!-- ─── 2. DETECTION SUMMARY BAR ─── -->
  <section class="sam-detect-summary">
    <div class="sam-detect-summary__inner">
      <div class="sam-detect-summary__grid">
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Asset</span>
          <span class="sam-detect-summary__value">Runout table roller</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Fault detected</span>
          <span class="sam-detect-summary__value">Loose cardan shaft coupling</span>
        </div>
        <div class="sam-detect-summary__item">
          <span class="sam-detect-summary__label">Industry</span>
          <span class="sam-detect-summary__value">Steel manufacturing</span>
        </div>
        <div class="sam-detect-summary__item sam-detect-summary__item--highlight">
          <span class="sam-detect-summary__label">Time to detection</span>
          <span class="sam-detect-summary__value kpi-value">Same day</span>
        </div>
      </div>
    </div>
  </section>


  <!-- ─── 3. THE STORY ─── -->
  <section class="sam-detect-story">
    <div class="sam-detect-story__inner">
      <div class="sam-detect-story__block">
        <p class="overline">The situation</p>
        <h2>What was at stake</h2>
        <p class="sam-detect-story__text">A hot strip mill customer installed SAM4 on a new runout table roller. The roll and its motor were identical to others SAM4 had been monitoring at the facility for two and a half years — giving the system a deep pool of baseline data in its library of failure signatures.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">What SAM4 detected</p>
        <h2>The signal and the diagnosis</h2>
        <p class="sam-detect-story__text">When the first measurements came in, SAM4 immediately flagged the asset. The noise floor around the supply frequency and the roll's rotational frequency were both elevated — clear indicators of a loose coupling, based on confirmed detections in identical rolls. Normally SAM4 needs a four-week training phase for new assets, but the existing 2.5 years of data from similar rolls made instant diagnosis possible. Two days later the customer confirmed the cardan joint was loose and replaced it.</p>
      </div>
      <div class="sam-detect-story__block">
        <p class="overline">The outcome</p>
        <h2>What happened next</h2>
        <p class="sam-detect-story__text">Same-day detection on a newly installed asset. The value of SAM4 increases over time as its library of failure signatures grows. The more assets it monitors and the longer it monitors them, the faster and more accurate its diagnoses become.</p>
      </div>
    </div>
  </section>


  <!-- ─── QUOTE ─── -->
  <section class="sam-detect-quote">
    <div class="sam-detect-quote__inner">
      <blockquote class="sam-detect-quote__blockquote">
        <p class="sam-detect-quote__text">&ldquo;SAM4 is proven technology creating clear value for our business. And that value just goes up the longer we use it.&rdquo;</p>
        <footer class="sam-detect-quote__attribution">
          <span class="sam-detect-quote__name">Customer</span>
          <span class="sam-detect-quote__company">Hot strip mill operations</span>
        </footer>
      </blockquote>
    </div>
  </section>

  <!-- ─── CTA BLOCK ─── -->
  <section class="sam-cta-block sam-cta-block--detect sam-cta-block--detect-alt">
    <div class="sam-cta-block__inner">
      <h2 class="sam-cta-block__heading">See what SAM4 can detect on your assets</h2>
      <p class="sam-cta-block__sub">Every detection story above comes from a real deployment. Request a demo to see how SAM4 works on your equipment.</p>
      <div class="sam-cta-block__actions">
        <a href="/contact?intent=demo" class="sam-btn sam-btn--primary">Request a Demo</a>
        <a href="/proof" class="sam-btn sam-btn--outline">See All Proof</a>
      </div>
    </div>
  </section>


  <!-- ─── RELATED DETECTION STORIES ─── -->
  <section class="sam-detect-related sam-detect-related--alt">
    <div class="sam-detect-related__inner">
      <p class="overline">Related detection stories</p>
      <h2>More results from the field</h2>

      <div class="sam-detect-related__grid">
        <a href="/proof/cardan-shaft-coupling-roller" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Steel</span>
          <h3 class="sam-detect-related__card-title">Failing cardan shaft coupling</h3>
          <p class="sam-detect-related__card-outcome kpi-value">100% detection accuracy</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/bearing-failure-motor-roll" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Steel</span>
          <h3 class="sam-detect-related__card-title">Bearing failure in motor roll</h3>
          <p class="sam-detect-related__card-outcome kpi-value">7 months advance tracking</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
        <a href="/proof/thyssenkrupp" class="sam-detect-related__card">
          <span class="sam-detect-related__card-industry">Metals &amp; Mining</span>
          <h3 class="sam-detect-related__card-title">thyssenkrupp</h3>
          <p class="sam-detect-related__card-outcome kpi-value">Bearing fault in extreme environment</p>
          <span class="sam-detect-related__card-link">Read story &rarr;</span>
        </a>
      </div>
    </div>
  </section>

</main>
