}


/* ============================================================
   §6  RELATED DETECTION STORIES
   Default: Seashell (for pages WITHOUT quote — CTA white → related seashell)
   With quote: override to white (CTA seashell → related white)
   ============================================================ */
.sam-detect-related {
  background: var(--sam-seashell);
  padding: var(--sp-11) var(--sp-06);
}
.sam-detect-related__inner {
  max-width: 1120px;
