}
/* When a quote section is present, related goes white */
.sam-detect-related--alt {
  background: var(--sam-white);
}
.sam-detect-related .overline {
  color: var(--sam-space-cadet);  /* Space Cadet on seashell/white = 11.3:1+ ✓ */
}
.sam-detect-related h2 {
  font-family: var(--sam-font); font-size: 2rem; font-weight: 700;
  line-height: 1.2; color: var(--sam-space-cadet);
  margin: 0 0 var(--sp-08) 0;
}
.sam-detect-related__grid {
  display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--sp-07);
}
.sam-detect-related__card {
  display: flex; flex-direction: column; gap: var(--sp-04);
  background: var(--sam-white); border-radius: 8px;
  padding: var(--sp-07) var(--sp-06);
  text-decoration: none; color: inherit;
  border: 1px solid var(--sam-border-light);
  transition: box-shadow var(--ease), border-color var(--ease);
}
.sam-detect-related__card:hover {
  box-shadow: var(--shadow-md); border-color: var(--sam-space-cadet);
}
.sam-detect-related__card-industry {
  font-family: var(--sam-font); font-size: 0.75rem; font-weight: 600;
  letter-spacing: 0.06em; text-transform: uppercase;
  color: var(--sam-teal-dark);
}
.sam-detect-related__card-title {
  font-family: var(--sam-font); font-size: 1.125rem; font-weight: 700;
  color: var(--sam-space-cadet); margin: 0;
}
.sam-detect-related__card-outcome {
  font-size: 0.9375rem;
  color: var(--sam-space-cadet);  /* Space Cadet on white = 11.9:1 ✓ */
  margin: 0;
}
.sam-detect-related__card-link {
  font-family: var(--sam-font); font-size: 0.9375rem; font-weight: 600;
  color: var(--sam-orange-dark); margin-top: auto;
}


/* ============================================================
